'use client';

import Link from 'next/link';
import { useState, useEffect } from 'react';

const Header = () => {
  const [scrolled, setScrolled] = useState(false);
  // Логика для мобильного меню (позже)

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const headerClasses = scrolled 
    ? "py-3 bg-white/95 backdrop-blur-md border-b border-green-dark/10 shadow-soft" 
    : "py-4 bg-beige-light/90 backdrop-blur-md border-b border-green-dark/10";

  return (
    <header className={`fixed top-0 left-0 right-0 z-50 transition ${headerClasses}`}>
      <div className="container mx-auto px-6 max-w-7xl">
        <div className="flex items-center justify-between">
          <Link href="#" className="flex items-center gap-3 text-green-dark no-underline group">
            <div className="w-12 h-12 bg-green-main rounded-full flex items-center justify-center text-2xl transition group-hover:rotate-[-10deg] group-hover:scale-[1.05]">
              🪿
            </div>
            <span className="font-display text-2xl font-bold">
              Гусь Маркет
            </span>
          </Link>
          <nav className="hidden lg:flex items-center gap-10">
            {/* Навигационные ссылки */}
            <Link href="#about" className="nav-link">О нас</Link>
            <Link href="#products" className="nav-link">Продукция</Link>
            <Link href="#locations" className="nav-link">Локации</Link>
            <Link href="#reviews" className="nav-link">Отзывы</Link>
            <Link href="#farmers" className="nav-link">Фермерам</Link>
            <a href="https://instagram.com/gusmarket.by" target="_blank" className="btn-primary">
                Instagram
            </a>
          </nav>
          {/* Кнопка мобильного меню (позже) */}
        </div>
      </div>
    </header>
  );
};

export default Header;